const { chromium } = require('playwright');
const fs = require('fs');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const context = browser.contexts()[0];

  const apiData = [];
  const page = await context.newPage();

  // Intercept ALL responses (onetalk + alibaba + xiaoman)
  page.on('response', async (resp) => {
    try {
      const ct = resp.headers()['content-type'] || '';
      const u = resp.url();
      if (ct.includes('json') && (u.includes('onetalk') || u.includes('alibaba.com') || u.includes('xiaoman.cn'))) {
        const body = await resp.json().catch(() => null);
        if (body) apiData.push({ url: u, data: body });
      }
    } catch(e) {}
  });

  // Navigate directly to the onetalk PWA page (the iframe source)
  const otUrl = 'https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman';
  console.log('Navigating to onetalk...');
  await page.goto(otUrl, { waitUntil: 'networkidle', timeout: 20000 }).catch(() => {});
  await page.waitForTimeout(5000);
  console.log('URL:', page.url().substring(0, 150));
  console.log('APIs captured:', apiData.length);

  // Categorize APIs
  const categories = {};
  for (const a of apiData) {
    const u = a.url;
    let cat = 'other';
    if (u.includes('/message/') || u.includes('/chat/') || u.includes('/im/')) cat = 'message';
    else if (u.includes('/list') || u.includes('/contact') || u.includes('/recent')) cat = 'list';
    else if (u.includes('profile') || u.includes('user') || u.includes('account')) cat = 'user';
    else if (u.includes('setting') || u.includes('config')) cat = 'config';
    if (!categories[cat]) categories[cat] = [];
    categories[cat].push(a);
  }

  console.log('\n=== By category ===');
  for (const [cat, items] of Object.entries(categories)) {
    console.log('\n--- ' + cat + ' (' + items.length + ') ---');
    items.forEach(a => {
      const d = a.data;
      let extra = '';
      const candidates = [d?.data?.list, d?.data?.records, d?.list, d?.records, d?.data?.data?.list, d?.result?.list, d?.data?.data];
      for (const c of candidates) {
        if (Array.isArray(c) && c.length > 0) extra += ' [array:' + c.length + ']';
      }
      console.log('  ' + a.url.substring(0, 150) + extra);
    });
  }

  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  fs.writeFileSync('data/onetalk_explore_' + ts + '.json', JSON.stringify(apiData.slice(0, 50), null, 2));
  console.log('\nSaved exploration data');

  await page.close().catch(() => {});
  await browser.close().catch(() => {});
})().catch(e => { console.error(e.message); process.exit(1); });
"

