const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '..', 'data');
const CDP_URL = 'http://127.0.0.1:9222';

// ----- helpers -----

const SYSTEM_MSG_PATTERNS = [
  /automatic reception will no longer intervene/i,
  /自动接待将不再触发/,
  /Marco大模型翻译/,
  /阿里国际Marco大模型翻译/,
  /买家有流失风险/,
  /Buyer has churn risk/,
  /一旦离开平台发生纠纷或欺诈/,
  /由于您介入该会话/,
  /Due to your intervention in this session/,
  /AI给您生成了一条回复建议/,
  /You have a visitor\. Follow up/,
  /This buyer has been pre-screened/,
  /反馈/,
];

function isSystemMessage(text) {
  if (!text) return true;
  return SYSTEM_MSG_PATTERNS.some((p) => p.test(text));
}

function toUnix(ts) {
  if (!ts) return 0;
  if (typeof ts === 'number') return ts < 1e12 ? ts * 1000 : ts;
  return new Date(ts).getTime();
}

function daysAgo(ts) {
  return Math.round((Date.now() - toUnix(ts)) / 86400000 * 10) / 10;
}

// ----- main -----

(async () => {
  let browser;
  try {
    browser = await chromium.connectOverCDP(CDP_URL);
  } catch (e) {
    console.log('❌ 无法连接到Chrome CDP');
    console.log('   Win+R: "C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\Application\\chrome.exe" --remote-debugging-port=9222 --user-data-dir="C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome_CDP_Profile"');
    process.exit(1);
  }

  const context = browser.contexts()[0];
  const page = await context.newPage();

  // ---- step 1: capture onetalk APIs ----
  const rawApis = [];
  page.on('response', async (resp) => {
    try {
      const ct = resp.headers()['content-type'] || '';
      const u = resp.url();
      if (!ct.includes('json') && !u.includes('mtop')) return;
      if (!u.includes('alibaba.com') && !u.includes('onetalk') && !u.includes('xiaoman.cn')) return;
      const text = await resp.text().catch(() => null);
      if (!text || text.length < 30) return;
      rawApis.push({ url: u, body: text.substring(0, 250000) });
    } catch (e) { /* ignore */ }
  });

  console.log('=== OKKI CDP 抓取 v2 ===');
  console.log('连接 onetalk 数据源...');

  // Navigate to onetalk PWA (the actual data source behind OKKI)
  const otUrl = 'https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman';
  await page.goto(otUrl, { waitUntil: 'networkidle', timeout: 20000 }).catch(() => {});
  await page.waitForTimeout(5000);

  // Scroll the contact list to trigger lazy-loading of more contacts
  await page.evaluate(() => {
    const scrollEl = document.querySelector('[class*=scroll]') || document.querySelector('[class*=list]');
    if (scrollEl) {
      scrollEl.scrollTop = 0;
      scrollEl.scrollTop = 2000;
      scrollEl.scrollTop = 4000;
      scrollEl.scrollTop = 0;
    }
  }).catch(() => {});
  await page.waitForTimeout(3000);

  // ---- step 2: parse captured APIs ----

  // 2a: contact list
  let contactList = [];
  for (const r of rawApis) {
    if (!r.url.includes('contact.list.get')) continue;
    try {
      const d = JSON.parse(r.body);
      const list = d?.data?.protocolList || d?.data?.data?.protocolList || [];
      if (list.length > 0) {
        contactList = list;
        console.log(`联系人: ${list.length}人 (via contact.list.get)`);
        break;
      }
    } catch (e) { /* ignore */ }
  }

  // 2b: tag relations (maps contactAliId → tagId)
  const tagMap = new Map(); // contactAliId → [tagId, ...]
  for (const r of rawApis) {
    if (!r.url.includes('tag.relation.list.get')) continue;
    try {
      const d = JSON.parse(r.body);
      const list = d?.data?.protocolList || d?.data?.data?.protocolList || [];
      for (const item of list) {
        const cid = item.tagTargetId;
        if (!tagMap.has(cid)) tagMap.set(cid, []);
        tagMap.get(cid).push(item.tagId);
      }
    } catch (e) { /* ignore */ }
  }
  console.log(`标签映射: ${tagMap.size}人`);

  // 2c: chat events (latest message previews)
  const eventMap = new Map(); // contactAccountId → latest event
  for (const r of rawApis) {
    if (!r.url.includes('getlatestchatrelationevent')) continue;
    try {
      const d = JSON.parse(r.body);
      const obj = d?.object || d?.data?.object;
      if (obj) {
        const key = obj.contactAccountId || obj.contactVaccountId;
        if (key && (!eventMap.has(key) || obj.gmtModified > (eventMap.get(key).gmtModified || ''))) {
          eventMap.set(key, obj);
        }
      }
    } catch (e) { /* ignore */ }
  }
  console.log(`聊天事件: ${eventMap.size}人`);

  // 2d: fetchcard (inquiry cards with rich content)
  const cardMap = new Map(); // someKey → cards
  for (const r of rawApis) {
    if (!r.url.includes('fetchcard')) continue;
    try {
      const d = JSON.parse(r.body);
      const cards = d?.fbCardList || d?.data?.fbCardList || [];
      for (const card of cards) {
        const inquiry = card?.data?.inquiryCardDTO;
        if (inquiry?.buyerAccountId) {
          const existing = cardMap.get(inquiry.buyerAccountId) || [];
          existing.push(card);
          cardMap.set(inquiry.buyerAccountId, existing);
        }
      }
    } catch (e) { /* ignore */ }
  }
  console.log(`询盘卡: ${cardMap.size}人`);

  // 2e: unread counts from OKKI side
  let unreadMap = new Map(); // contactAliId → unreadCount
  for (const r of rawApis) {
    if (!r.url.includes('alibabaRead/unReadList')) continue;
    try {
      const d = JSON.parse(r.body);
      const data = d?.data || {};
      for (const [key, count] of Object.entries(data)) {
        unreadMap.set(parseInt(key), count);
      }
    } catch (e) { /* ignore */ }
  }

  // ---- step 3: merge into customer objects ----
  const customers = [];
  for (const c of contactList) {
    const cid = c.contactAliId || c.encryptContactAliId;
    const events = eventMap.get(cid);
    const cards = cardMap.get(cid) || [];
    const unread = unreadMap.get(cid) || 0;
    const tags = tagMap.get(String(cid)) || [];
    const lastTs = toUnix(c.modifiedTimeStamp || events?.gmtModified || 0);

    // Extract message content from cards or events
    let msgContent = '';
    let msgType = '';
    let msgTime = 0;

    // Prefer inquiry cards (richest content)
    for (const card of cards) {
      const d = card?.data;
      if (d?.richTextContent && d.richTextContent.length > (msgContent?.length || 0)) {
        msgContent = d.richTextContent;
        msgType = 'received';
        msgTime = toUnix(d?.inquiryCardDTO?.gmtModified) || lastTs;
      }
    }

    // Fall back to event data
    if (!msgContent && events) {
      msgContent = events.eventContent || '';
      msgType = events.sendType || '';
      msgTime = toUnix(events.gmtModified) || lastTs;
    }

    if (!msgTime) msgTime = lastTs;

    const name = c.displayName || '';
    const da = daysAgo(lastTs);

    customers.push({
      cid: String(cid),
      accountId: cid,
      name,
      countryCode: '',
      buyerLevel: '',
      unreadCount: unread,
      lastContactTime: lastTs,
      daysAgo: da,
      latestMessageContent: msgContent,
      latestMessageType: msgType,
      latestMessageTime: msgTime,
      isUnread: unread > 0,
      tagInfo: tags,
      contactRaw: c,
      events,
      cards,
    });
  }

  // Sort by last contact time (most recent first)
  customers.sort((a, b) => b.lastContactTime - a.lastContactTime);

  console.log(`合并结果: ${customers.length}人`);

  // ---- step 4: first-pass classification ----
  const now = Date.now();
  for (const c of customers) {
    const da = c.daysAgo;
    const hasUnread = c.isUnread;
    const msg = c.latestMessageContent || '';

    // Filter system messages
    if (isSystemMessage(msg)) {
      c._systemMsgBlocked = true;
    }

    if (hasUnread) {
      c.priority = 'P0';
      c.tier = 'S';
      c.reasons = ['有未读消息'];
    } else if (da <= 3) {
      c.priority = 'P0';
      c.tier = 'A';
      c.reasons = ['未读+3天内'];
    } else if (da <= 7) {
      c.priority = 'P1';
      c.tier = 'B';
      c.reasons = ['7天内活跃'];
    } else if (da <= 30) {
      c.priority = 'P2';
      c.tier = 'C';
      c.reasons = ['30天内互动'];
    } else {
      c.priority = 'P3';
      c.tier = 'D';
      c.reasons = ['超30天'];
    }
  }

  // ---- step 5: save ----
  const ts = new Date().toISOString().replace(/[:.]/g, '-');

  // Full data
  const output = {
    capturedAt: new Date().toISOString(),
    method: 'cdp_v2_onetalk',
    stats: {
      total: customers.length,
      p0: customers.filter((c) => c.priority === 'P0').length,
      p1: customers.filter((c) => c.priority === 'P1').length,
      unread: customers.filter((c) => c.isUnread).length,
      systemBlocked: customers.filter((c) => c._systemMsgBlocked).length,
    },
    customers,
  };

  fs.writeFileSync(
    path.join(DATA_DIR, `extracted_${ts}.json`),
    JSON.stringify(output, null, 2)
  );

  // P0+P1 only (for quick analysis)
  const p0p1 = customers.filter((c) => c.priority === 'P0' || c.priority === 'P1');
  fs.writeFileSync(
    path.join(DATA_DIR, `p0p1_${ts}.json`),
    JSON.stringify(p0p1, null, 2)
  );

  console.log(`\n=== 抓取完成 ===`);
  console.log(`全量: ${customers.length}人 → extracted_${ts}.json`);
  console.log(`P0+P1: ${p0p1.length}人 → p0p1_${ts}.json`);
  console.log(`统计: P0=${output.stats.p0} P1=${output.stats.p1} 未读=${output.stats.unread} 系统消息=${output.stats.systemBlocked}`);

  await page.close().catch(() => {});
  await browser.close().catch(() => {});
  console.log('已断开CDP');
})().catch((err) => {
  console.error('脚本错误:', err.message);
  process.exit(1);
});

