const { chromium } = require('playwright');
const fs = require('fs');
(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const page = await browser.contexts()[0].newPage();

  await page.goto('https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman',
    { waitUntil: 'networkidle', timeout: 20000 }).catch(() => {});
  await page.waitForTimeout(6000);

  // Try to extract from window/global state, IndexedDB, and DOM
  const extracted = await page.evaluate(() => {
    const result = { methods: {} };

    // Method 1: Check window properties for data stores
    const winKeys = Object.keys(window).filter(k => 
      k.toLowerCase().includes('store') || k.toLowerCase().includes('state') ||
      k.toLowerCase().includes('redux') || k.toLowerCase().includes('contact') ||
      k.toLowerCase().includes('model') || k.includes('__')
    );
    result.methods.windowKeys = winKeys.slice(0, 20);

    // Method 2: Check for React fiber
    const rootEl = document.getElementById('root') || document.querySelector('[class*=app]');
    if (rootEl) {
      const fiberKey = Object.keys(rootEl).find(k => k.startsWith('__react'));
      result.methods.hasReactFiber = !!fiberKey;
    }

    // Method 3: Try to access common Alibaba data stores
    try {
      if (window.__ICBU_DATA__) result.methods.hasIcbuData = true;
    } catch(e) {}

    // Method 4: DOM scraping - get visible contact items
    const contactItems = [];
    const items = document.querySelectorAll('[class*=contact], [class*=chat-item], [class*=conversation]');
    items.forEach(el => {
      const text = el.textContent?.trim().substring(0, 200);
      if (text && text.length > 5) contactItems.push(text);
    });
    result.methods.domContactCount = contactItems.length;
    result.methods.domSamples = contactItems.slice(0, 3);

    // Method 5: LocalStorage
    try {
      const lsKeys = [];
      for (let i = 0; i < localStorage.length; i++) {
        lsKeys.push(localStorage.key(i));
      }
      result.methods.localStorageKeys = lsKeys.slice(0, 20);
    } catch(e) {}

    // Method 6: try model/state vars used by alibaba
    const varNames = ['__INITIAL_STATE__', '__DATA__', '__PRELOADED_STATE__', 'store', '_store'];
    for (const name of varNames) {
      try {
        if (window[name]) result.methods['has_' + name] = true;
      } catch(e) {}
    }

    return result;
  });

  console.log(JSON.stringify(extracted, null, 2));

  await page.close().catch(() => {});
  await browser.close().catch(() => {});
})().catch(e => console.error(e.message));
