  const contacts = await page.evaluate(() => {
    const results = [];

    // Find all contact items - the onetalk sidebar has a virtual list
    // Each item is a div with specific structure
    const allEls = document.querySelectorAll('*');
    const contactItems = new Set();

    // Strategy: find all elements whose textContent includes a known pattern
    // like "[未读]" or "[已读]" or time patterns like "HH:MM"
    for (const el of allEls) {
      const text = el.textContent || '';
      // Check if this looks like a contact card (has name + time + message)
      const hasUnreadTag = text.includes('[未读]') || text.includes('[已读]');
      const hasTimePattern = /\d{1,2}:\d{2}/.test(text);
      const hasDatePattern = /\d{4}-\d{1,2}-\d{1,2}/.test(text);
      if ((hasUnreadTag || hasTimePattern || hasDatePattern) && el.children.length > 2) {
        contactItems.add(el);
      }
    }

