          msg = msgEl.textContent.trim();
        } else {
          // Get from text after name/time
          const parts = fullText.split(/[未读]|[已读]/);
          if (parts.length > 1) {
            msg = parts[parts.length - 1].trim();
          }
        }

        // Detect unread
        const isUnread = fullText.includes('[未读]');

        // Detect if this is a system message
        const isSystem = /automatic reception|自动接待|Marco大模型|买家有流失|纠纷或欺诈|介入该会话|intervene in this session/i.test(msg);

        // Extract time
